@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/metadata/geo-dataset-001> ;
            sh:resultMessage "DDE metadata record should declare conformance to https://w3id.org/cdif/bbr/metadata/DDEproperties/ddeMandatory" ;
            sh:resultPath ( schema1:subjectOf dcterms:conformsTo ) ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:HasValueConstraintComponent ;
            sh:sourceShape [ sh:hasValue <https://w3id.org/cdif/bbr/metadata/DDEproperties/ddeMandatory> ;
                    sh:message "DDE metadata record should declare conformance to https://w3id.org/cdif/bbr/metadata/DDEproperties/ddeMandatory" ;
                    sh:path ( schema1:subjectOf dcterms:conformsTo ) ;
                    sh:severity sh:Warning ] ] .
